{"content":"'use client';

import { useEffect, useState } from 'react';
import { createClient } from '@/lib/supabase/client';
import type { User } from '@supabase/supabase-js';
import type { Profile } from '@/types';

export function useUser() {
  const [user, setUser] = useState<User | null>(null);
  const [profile, setProfile] = useState<Profile | null>(null);
  const [loading, setLoading] = useState(true);
  const supabase = createClient();

  useEffect(() => {
    const getUser = async () => {
      const { data: { user } } = await supabase.auth.getUser();
      setUser(user);

      if (user) {
        const { data } = await supabase
          .from('profiles')
          .select('*')
          .eq('id', user.id)
          .single();
        setProfile(data);
      }

      setLoading(false);
    };

    getUser();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      async (_event, session) => {
        setUser(session?.user ?? null);
        if (session?.user) {
          const { data } = await supabase
            .from('profiles')
            .select('*')
            .eq('id', session.user.id)
            .single();
          setProfile(data);
        } else {
          setProfile(null);
        }
      }
    );

    return () => subscription.unsubscribe();
  }, []);

  return { user, profile, loading };
}
"}

{"content":"-- ============================================================================
-- NexusAI - Initial Database Schema
-- Migration: 001_initial_schema.sql
-- Description: Complete database schema with tables, RLS policies, triggers,
--              indexes, and storage buckets for the NexusAI platform.
-- ============================================================================

-- Enable UUID extension
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- ============================================================================
-- TABLES
-- ============================================================================

-- Profiles table (extends auth.users)
CREATE TABLE public.profiles (
  id UUID PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  email TEXT NOT NULL,
  full_name TEXT,
  avatar_url TEXT,
  organization_id UUID,
  role TEXT DEFAULT 'member' CHECK (role IN ('owner', 'admin', 'member')),
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- Organizations table (team workspaces with plan info)
CREATE TABLE public.organizations (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  slug TEXT UNIQUE NOT NULL,
  stripe_customer_id TEXT,
  stripe_subscription_id TEXT,
  plan TEXT DEFAULT 'free' CHECK (plan IN ('free', 'pro', 'enterprise')),
  plan_period_end TIMESTAMPTZ,
  doc_quota INTEGER DEFAULT 10,
  survey_quota INTEGER DEFAULT 5,
  doc_used INTEGER DEFAULT 0,
  survey_used INTEGER DEFAULT 0,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Add FK from profiles to organizations (after both tables exist)
ALTER TABLE public.profiles
  ADD CONSTRAINT profiles_organization_id_fkey
  FOREIGN KEY (organization_id) REFERENCES public.organizations(id) ON DELETE SET NULL;

-- Documents table (uploaded files with status tracking)
CREATE TABLE public.documents (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id UUID NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  uploaded_by UUID NOT NULL REFERENCES public.profiles(id),
  file_name TEXT NOT NULL,
  file_url TEXT NOT NULL,
  file_size INTEGER,
  file_type TEXT,
  status TEXT DEFAULT 'pending' CHECK (status IN ('pending', 'processing', 'completed', 'failed')),
  extracted_data JSONB,
  template_id UUID,
  processing_time_ms INTEGER,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Extraction Templates table (field definitions for doc extraction)
CREATE TABLE public.extraction_templates (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id UUID NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  description TEXT,
  fields JSONB NOT NULL DEFAULT '[]',
  category TEXT CHECK (category IN ('invoice', 'contract', 'receipt', 'custom')),
  is_default BOOLEAN DEFAULT false,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Add FK for documents.template_id (after extraction_templates exists)
ALTER TABLE public.documents
  ADD CONSTRAINT documents_template_id_fkey
  FOREIGN KEY (template_id) REFERENCES public.extraction_templates(id) ON DELETE SET NULL;

-- Surveys table (survey definitions with questions as JSONB)
CREATE TABLE public.surveys (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id UUID NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  created_by UUID NOT NULL REFERENCES public.profiles(id),
  title TEXT NOT NULL,
  description TEXT,
  questions JSONB NOT NULL DEFAULT '[]',
  status TEXT DEFAULT 'draft' CHECK (status IN ('draft', 'active', 'closed')),
  settings JSONB DEFAULT '{"anonymous": true, "allowMultiple": false, "closeDate": null}',
  response_count INTEGER DEFAULT 0,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- Survey Responses table (respondent answers)
CREATE TABLE public.survey_responses (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  survey_id UUID NOT NULL REFERENCES public.surveys(id) ON DELETE CASCADE,
  answers JSONB NOT NULL,
  respondent_email TEXT,
  metadata JSONB,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Analyses table (cached AI analysis results)
CREATE TABLE public.analyses (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  survey_id UUID NOT NULL REFERENCES public.surveys(id) ON DELETE CASCADE,
  analysis_type TEXT NOT NULL CHECK (analysis_type IN ('themes', 'sentiment', 'summary', 'full')),
  results JSONB NOT NULL,
  model_used TEXT DEFAULT 'gpt-4o',
  tokens_used INTEGER,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- API Keys table (API key management)
CREATE TABLE public.api_keys (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id UUID NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  key_hash TEXT NOT NULL,
  key_prefix TEXT NOT NULL,
  last_used_at TIMESTAMPTZ,
  expires_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Activity Log table (audit trail)
CREATE TABLE public.activity_log (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id UUID NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  user_id UUID REFERENCES public.profiles(id),
  action TEXT NOT NULL,
  resource_type TEXT CHECK (resource_type IN ('document', 'survey', 'template')),
  resource_id UUID,
  metadata JSONB,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- ============================================================================
-- HELPER FUNCTIONS (after tables exist)
-- ============================================================================

CREATE OR REPLACE FUNCTION public.is_org_member(org_id UUID)
RETURNS BOOLEAN AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.profiles
    WHERE id = auth.uid() AND organization_id = org_id
  );
$$ LANGUAGE sql SECURITY DEFINER STABLE;

-- ============================================================================
-- INDEXES
-- ============================================================================

CREATE INDEX idx_profiles_org ON public.profiles(organization_id);
CREATE INDEX idx_documents_org ON public.documents(organization_id);
CREATE INDEX idx_documents_status ON public.documents(status);
CREATE INDEX idx_templates_org ON public.extraction_templates(organization_id);
CREATE INDEX idx_surveys_org ON public.surveys(organization_id);
CREATE INDEX idx_surveys_status ON public.surveys(status);
CREATE INDEX idx_responses_survey ON public.survey_responses(survey_id);
CREATE INDEX idx_analyses_survey ON public.analyses(survey_id);
CREATE INDEX idx_api_keys_org ON public.api_keys(organization_id);
CREATE INDEX idx_api_keys_hash ON public.api_keys(key_hash);
CREATE INDEX idx_activity_org ON public.activity_log(organization_id);

-- ============================================================================
-- TRIGGERS
-- ============================================================================

-- Trigger: auto-create profile on auth.users signup
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER AS $$
BEGIN
  INSERT INTO public.profiles (id, email, full_name, avatar_url)
  VALUES (
    NEW.id,
    NEW.email,
    COALESCE(NEW.raw_user_meta_data->>'full_name', NEW.raw_user_meta_data->>'name'),
    NEW.raw_user_meta_data->>'avatar_url'
  );
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

-- Trigger: increment survey response_count on new response
CREATE OR REPLACE FUNCTION public.handle_new_response()
RETURNS TRIGGER AS $$
BEGIN
  UPDATE public.surveys
  SET response_count = response_count + 1,
      updated_at = now()
  WHERE id = NEW.survey_id;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

CREATE TRIGGER on_survey_response_created
  AFTER INSERT ON public.survey_responses
  FOR EACH ROW EXECUTE FUNCTION public.handle_new_response();

-- ============================================================================
-- ROW LEVEL SECURITY
-- ============================================================================

-- Enable RLS on all tables
ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.organizations ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.documents ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.extraction_templates ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.surveys ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.survey_responses ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.analyses ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.api_keys ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.activity_log ENABLE ROW LEVEL SECURITY;

-- RLS: Profiles
CREATE POLICY "Users can view own profile" ON public.profiles
  FOR SELECT USING (id = auth.uid());
CREATE POLICY "Users can update own profile" ON public.profiles
  FOR UPDATE USING (id = auth.uid());
CREATE POLICY "Users can view org members" ON public.profiles
  FOR SELECT USING (
    organization_id IN (
      SELECT organization_id FROM public.profiles WHERE id = auth.uid()
    )
  );

-- RLS: Organizations
CREATE POLICY "Members can view their org" ON public.organizations
  FOR SELECT USING (public.is_org_member(id));
CREATE POLICY "Owners can update org" ON public.organizations
  FOR UPDATE USING (
    id IN (
      SELECT organization_id FROM public.profiles
      WHERE id = auth.uid() AND role = 'owner'
    )
  );
CREATE POLICY "Users can create orgs" ON public.organizations
  FOR INSERT WITH CHECK (true);

-- RLS: Documents
CREATE POLICY "Members can view documents" ON public.documents
  FOR SELECT USING (public.is_org_member(organization_id));
CREATE POLICY "Members can insert documents" ON public.documents
  FOR INSERT WITH CHECK (public.is_org_member(organization_id));
CREATE POLICY "Members can update documents" ON public.documents
  FOR UPDATE USING (public.is_org_member(organization_id));
CREATE POLICY "Uploaders can delete documents" ON public.documents
  FOR DELETE USING (uploaded_by = auth.uid());

-- RLS: Extraction Templates
CREATE POLICY "Members can view templates" ON public.extraction_templates
  FOR SELECT USING (public.is_org_member(organization_id));
CREATE POLICY "Members can manage templates" ON public.extraction_templates
  FOR ALL USING (public.is_org_member(organization_id));

-- RLS: Surveys
CREATE POLICY "Members can view surveys" ON public.surveys
  FOR SELECT USING (public.is_org_member(organization_id));
CREATE POLICY "Members can manage surveys" ON public.surveys
  FOR ALL USING (public.is_org_member(organization_id));

-- RLS: Survey Responses (public INSERT for active surveys, SELECT for org members)
CREATE POLICY "Anyone can submit responses" ON public.survey_responses
  FOR INSERT WITH CHECK (
    survey_id IN (SELECT id FROM public.surveys WHERE status = 'active')
  );
CREATE POLICY "Members can view responses" ON public.survey_responses
  FOR SELECT USING (
    survey_id IN (
      SELECT id FROM public.surveys WHERE public.is_org_member(organization_id)
    )
  );

-- RLS: Analyses
CREATE POLICY "Members can view analyses" ON public.analyses
  FOR SELECT USING (
    survey_id IN (
      SELECT id FROM public.surveys WHERE public.is_org_member(organization_id)
    )
  );
CREATE POLICY "Members can create analyses" ON public.analyses
  FOR INSERT WITH CHECK (
    survey_id IN (
      SELECT id FROM public.surveys WHERE public.is_org_member(organization_id)
    )
  );

-- RLS: API Keys
CREATE POLICY "Members can view api keys" ON public.api_keys
  FOR SELECT USING (public.is_org_member(organization_id));
CREATE POLICY "Admins can manage api keys" ON public.api_keys
  FOR ALL USING (
    organization_id IN (
      SELECT organization_id FROM public.profiles
      WHERE id = auth.uid() AND role IN ('owner', 'admin')
    )
  );

-- RLS: Activity Log
CREATE POLICY "Members can view activity" ON public.activity_log
  FOR SELECT USING (public.is_org_member(organization_id));
CREATE POLICY "Members can insert activity" ON public.activity_log
  FOR INSERT WITH CHECK (public.is_org_member(organization_id));

-- ============================================================================
-- STORAGE BUCKETS
-- ============================================================================

-- Create private storage buckets for document uploads and exports
INSERT INTO storage.buckets (id, name, public) VALUES ('documents', 'documents', false);
INSERT INTO storage.buckets (id, name, public) VALUES ('exports', 'exports', false);

-- Storage policies: org members can manage their own files
CREATE POLICY "Org members can upload documents"
  ON storage.objects FOR INSERT
  WITH CHECK (
    bucket_id = 'documents'
    AND public.is_org_member((storage.foldername(name))[1]::UUID)
  );

CREATE POLICY "Org members can view documents"
  ON storage.objects FOR SELECT
  USING (
    bucket_id = 'documents'
    AND public.is_org_member((storage.foldername(name))[1]::UUID)
  );

CREATE POLICY "Org members can delete documents"
  ON storage.objects FOR DELETE
  USING (
    bucket_id = 'documents'
    AND public.is_org_member((storage.foldername(name))[1]::UUID)
  );

CREATE POLICY "Org members can view exports"
  ON storage.objects FOR SELECT
  USING (
    bucket_id = 'exports'
    AND public.is_org_member((storage.foldername(name))[1]::UUID)
  );

CREATE POLICY "Org members can upload exports"
  ON storage.objects FOR INSERT
  WITH CHECK (
    bucket_id = 'exports'
    AND public.is_org_member((storage.foldername(name))[1]::UUID)
  );
"}

